/* Given a string, find out how many distinct characters (regardless of case) does it consist of
  >>> countDistinctCharacters('xyzXYZ')
  3
  >>> countDistinctCharacters('Jerry')
  4
  */
const countDistinctCharacters = (string) => {
  // remove duplicates
  const charArray = string.split('');
  const distinctCharArray = [...new Set(charArray)];
  // map into an object with keys as distinct characters, values as number of occurence
  const charObject = distinctCharArray.reduce((obj, char) => {
    obj[char.toLowerCase()] = 0;
    return obj;
  }, {});
  // loop through the string, adding 1 to the value of each character in the object if it is found in the string
  for (let i = 0; i < charArray.length; i++) {
    const char = charArray[i];
    if (charObject[char.toLowerCase()]) {
      charObject[char.toLowerCase()] += 1;
    }
  }
  // count the number of keys in the object, which is the number of distinct characters
  const distinctCharCount = Object.keys(charObject).length;
  return distinctCharCount;
};

module.exports = countDistinctCharacters;

